$sqlTiendas = "SELECT t.*, c.nombre AS categoria FROM marketplace_tiendas t LEFT JOIN categorias c ON c.id=t.categoria_id WHERE t.activo=1";
$paramsTiendas = [];
if(!empty($empresaId)){ $sqlTiendas .= " AND t.empresa_id = ?"; $paramsTiendas[] = $empresaId; }
